import {
  discoverOriginSchema,
  GuidanceMode,
  type HttpMethod,
  type AuthMode,
} from '@agentcash/discovery';

import { log } from '@/shared/log';
import z from 'zod';
import { TOOL_PARAMS } from '@/shared/descriptions';
import { zodUrl } from '@/shared/url';
import { getBaseUrl } from '@/shared/utils';
import type { GlobalFlags } from '@/types';

export const discoverResourcesSchema = z.object({
  url: zodUrl.describe(TOOL_PARAMS.discoverApiEndpoints.url),
  includeGuidance: z
    .boolean()
    .optional()
    .describe(TOOL_PARAMS.discoverApiEndpoints.includeGuidance),
});

export type DiscoverResourcesInput = z.input<typeof discoverResourcesSchema>;

/**
 * Discover payment-protected resources on an origin.
 * Fetches OpenAPI spec, builds endpoint index, and fetches guidance.
 *
 * Returns DiscoverOriginSchemaSuccess on success, DiscoverOriginSchemaNotFound with cause on failure.
 */
export interface DiscoverOptions {
  flags?: GlobalFlags;
}

export async function discoverResources(
  surface: string,
  args: DiscoverResourcesInput,
  options?: DiscoverOptions
) {
  const parsedArgs = discoverResourcesSchema.safeParse(args);
  if (!parsedArgs.success) {
    return {
      found: false as const,
      cause: 'invalid_input' as const,
      message: parsedArgs.error.message,
    };
  }

  const { url, includeGuidance } = parsedArgs.data;

  const guidance =
    includeGuidance === true
      ? GuidanceMode.Always
      : includeGuidance === false
        ? GuidanceMode.Never
        : GuidanceMode.Auto;

  const result = await discoverOriginSchema({ target: url, guidance });

  if (result.found) {
    return {
      ...result,
      endpoints: result.endpoints.map(e => ({ ...e })),
    };
  }

  // Fallback: check agentcash server for scan-derived endpoints
  const scanResult = await fetchScanEndpoints(
    url,
    options?.flags?.dev ?? false
  );
  if (scanResult) {
    log.info(
      `[discoverResources] scan fallback found ${scanResult.endpoints.length} endpoints for ${url}`
    );
    return scanResult;
  }

  log.error(`[discoverResources] failed`, {
    surface,
    url,
    cause: result.cause,
    message: result.message,
  });
  return result;
}

const scanEndpointSchema = z.object({
  method: z.string(),
  path: z.string(),
  summary: z.string().optional().default(''),
  authMode: z.string().optional(),
  price: z.string().optional(),
});

const scanResponseSchema = z.object({
  origin: z.string(),
  title: z.string().optional().default(''),
  description: z.string().optional().default(''),
  endpoints: z.array(scanEndpointSchema),
});

async function fetchScanEndpoints(origin: string, dev: boolean) {
  const baseUrl = getBaseUrl(dev);
  const url = `${baseUrl}/api/discover/scan?origin=${encodeURIComponent(origin)}`;

  return fetch(url, {
    signal: AbortSignal.timeout(5_000),
  })
    .then(async res => {
      if (!res.ok) return null;

      const data = scanResponseSchema.safeParse(await res.json());
      if (!data.success || data.data.endpoints.length === 0) return null;

      return {
        found: true as const,
        origin: data.data.origin,
        source: 'scan' as const,
        info: {
          title: data.data.title,
          description: data.data.description,
        },
        endpoints: data.data.endpoints.map(e => ({
          path: e.path,
          method: (e.method || 'GET').toUpperCase() as HttpMethod,
          summary: e.summary,
          authMode: (e.authMode as AuthMode) ?? undefined,
          protocols: ['x402' as const],
          price: e.price,
        })),
        guidanceAvailable: false,
        guidanceTokens: 0,
        guidance: undefined,
      };
    })
    .catch(() => null);
}
